      // Track number of sessions used
      sessionsLimit: varchar("sessions_limit", { length: 10 }),
      // Limit for free trial (null for unlimited)
      minutesUsed: varchar("minutes_used", { length: 10 }).notNull().default("0"),
      // Track total minutes used
      minutesLimit: varchar("minutes_limit", { length: 10 }),
      // 180 minutes for free trial (null for unlimited)
      sessionHistory: jsonb("session_history").default([]),
      // Array of { sessionId, startTime, endTime, durationMinutes }
      currentPeriodStart: timestamp("current_period_start"),
      currentPeriodEnd: timestamp("current_period_end"),
      canceledAt: timestamp("canceled_at"),
