    trainingDocuments = pgTable("training_documents", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      domainExpertiseId: varchar("domain_expertise_id").references(() => domainExpertise.id).notNull(),
      userId: varchar("user_id").references(() => authUsers.id).notNull(),
      fileName: varchar("file_name", { length: 255 }).notNull(),
      fileType: varchar("file_type", { length: 20 }).notNull(),
      // pdf, doc, docx, txt, xls, xlsx, ppt, pptx, url, mp3, wav, m4a, ogg, webm, flac
      fileUrl: text("file_url").notNull(),
      // Object storage URL or web URL
      content: text("content"),
      // Extracted text content (or transcription for audio)
      contentSource: varchar("content_source", { length: 20 }).default("extraction"),
      // 'extraction' for documents, 'transcription' for audio
      audioDuration: integer("audio_duration"),
      // Duration in seconds for audio files
      summary: jsonb("summary"),
      // AI-generated summary bullets (array of strings)
      summaryStatus: varchar("summary_status", { length: 20 }).default("not_generated"),
      // not_generated, generating, completed, failed
      summaryError: text("summary_error"),
      // Error message if summary generation failed
      lastSummarizedAt: timestamp("last_summarized_at"),
      // When the summary was last generated
      metadata: jsonb("metadata").default({}),
      // fileSize, mimeType, transcription confidence, etc.
      processingStatus: varchar("processing_status", { length: 20 }).notNull().default("pending"),
      // pending, processing, transcribing, completed, failed
      processingError: text("processing_error"),
      // Error message if processing failed
      knowledgeExtractedAt: timestamp("knowledge_extracted_at"),
      // When knowledge was extracted from this document
      contentHash: varchar("content_hash", { length: 64 }),
      // SHA-256 hash of content for change detection
      uploadedAt: timestamp("uploaded_at").defaultNow(),
      updatedAt: timestamp("updated_at").defaultNow()
    });
