      async updateUserStatus(userId, status, reason) {
        await db.update(authUsers).set({ status, updatedAt: /* @__PURE__ */ new Date() }).where(eq(authUsers.id, userId));
        await db.insert(auditLogs).values({
          actorId: userId,
          action: `user.status.${status}`,
          targetType: "user",
          targetId: userId,
          metadata: { reason, previousStatus: status }
        });
      }
      async grantTimeExtension(userId, extensionType, extensionValue, reason, grantedBy, expiresAt) {
        await db.insert(timeExtensions).values({
          userId,
          extensionType,
          extensionValue,
          reason,
          grantedBy,
          status: "active",
          expiresAt
        });
        if (extensionType === "trial_extension") {
          const subscription = await this.getSubscriptionByUserId(userId);
          if (subscription) {
            const currentEnd = subscription.currentPeriodEnd || /* @__PURE__ */ new Date();
            const newEnd = new Date(currentEnd);
            newEnd.setDate(newEnd.getDate() + parseInt(extensionValue));
            await db.update(subscriptions).set({
              currentPeriodEnd: newEnd,
              updatedAt: /* @__PURE__ */ new Date()
            }).where(eq(subscriptions.userId, userId));
          }
        } else if (extensionType === "minutes_addition") {
          await this.grantMinutes(userId, parseInt(extensionValue), reason, 30);
        }
        await db.insert(auditLogs).values({
          actorId: grantedBy,
          action: "user.time_extension.granted",
          targetType: "user",
          targetId: userId,
          metadata: { extensionType, extensionValue, reason }
        });
      }
      async getUserSessionHistory(userId, limit = 50) {
        const result = await db.execute(sql2`
      SELECT 
        id,
        user_id,
        session_id,
        start_time,
        end_time,
        duration_seconds,
        status,
        created_at
      FROM ${sessionUsage}
      WHERE user_id = ${userId}
      ORDER BY start_time DESC
      LIMIT ${limit}
    `);
        return result.rows.map((row) => ({
          id: row.id,
          userId: row.user_id,
          sessionId: row.session_id,
          startTime: row.start_time,
          endTime: row.end_time,
          durationSeconds: row.duration_seconds,
          status: row.status,
          createdAt: row.created_at
        }));
      }
      async getUserTimeExtensions(userId) {
        const extensions = await db.execute(sql2`
      SELECT 
        te.*,
        u.first_name || ' ' || u.last_name as granted_by_name,
        u.email as granted_by_email
      FROM ${timeExtensions} te
      JOIN ${authUsers} u ON te.granted_by = u.id
      WHERE te.user_id = ${userId}
      ORDER BY te.created_at DESC
    `);
        return extensions.rows;
      }
