        engineName = aiConfig.engine;
        originalModel = model;
        const fastModel = model.includes("gpt-4") ? "gpt-4o-mini" : model.includes("claude") ? "claude-3-5-haiku-latest" : model.includes("gemini") ? "gemini-2.0-flash" : model;
