// server/routes-transcription.ts
import { Router } from "express";
import { WebSocketServer, WebSocket } from "ws";
import { createClient, LiveTranscriptionEvents } from "@deepgram/sdk";
function setupTranscriptionRoutes(server) {
  const router4 = Router();
  const wss = new WebSocketServer({ noServer: true });
  server.on("upgrade", (request, socket, head) => {
    if (request.url === "/api/transcribe-stream") {
      wss.handleUpgrade(request, socket, head, (ws2) => {
        wss.emit("connection", ws2, request);
      });
    }
  });
  wss.on("connection", async (clientWs) => {
    console.log("\u{1F3A4} Client connected to transcription stream");
    const apiKey = process.env.DEEPGRAM_API_KEY;
    if (!apiKey) {
      clientWs.send(JSON.stringify({
        type: "error",
        error: "Transcription service not configured. Please contact administrator."
      }));
      clientWs.close();
      return;
    }
    try {
      const deepgram = createClient(apiKey);
      const dgConnection = deepgram.listen.live({
        model: "nova-2-meeting",
        // MEETING-OPTIMIZED: Better multi-speaker detection
        language: "en-US",
        // US English for better accuracy
        smart_format: true,
        // Automatic formatting of dates, times, numbers
        punctuate: true,
        // Automatic punctuation
        diarize: true,
        // Multi-speaker identification (requires 20-30s warmup)
        utterances: true,
        // IMPROVED: Semantic segments with speaker labels
        interim_results: true,
        // Real-time partial results for low latency
        endpointing: 300,
        // 300ms pause detection for speaker turns
        vad_events: true,
        // Voice Activity Detection events for better flow
        encoding: "linear16",
        // PCM16 encoding
        sample_rate: 48e3,
        // FIXED: Match client's 48kHz for better speaker detection
        channels: 1,
        // Mono audio (meeting audio is pre-mixed)
        filler_words: false,
        // Skip filler words for cleaner output
        utterance_end_ms: 1e3,
        // 1s for faster turnaround
        numerals: true,
        // Convert numbers to numerals
        profanity_filter: false,
        // Keep original speech
        redact: false,
        // No redaction
        detect_entities: false
        // Disable entity detection for faster processing
      });
      console.log("\u{1F399}\uFE0F Deepgram configured with nova-2-meeting model for multi-speaker diarization");
      dgConnection.on(LiveTranscriptionEvents.Error, (error) => {
        console.error("\u274C Deepgram connection error:", error);
        console.error("\u274C Deepgram error details:", JSON.stringify(error, null, 2));
        try {
          if (dgConnection.getReadyState() !== 3) {
            dgConnection.finish();
          }
        } catch (cleanupError) {
          console.error("Error cleaning up Deepgram connection:", cleanupError);
        }
        if (clientWs.readyState === WebSocket.OPEN) {
          try {
            clientWs.send(JSON.stringify({
              type: "error",
              error: "Transcription service error. Please try again."
            }));
            clientWs.close();
          } catch (wsError) {
            console.error("Error sending error message to client:", wsError);
          }
        }
      });
      dgConnection.on(LiveTranscriptionEvents.Close, () => {
        console.log("\u{1F50C} Deepgram connection closed");
      });
      dgConnection.on(LiveTranscriptionEvents.Open, () => {
        console.log("\u2705 Deepgram connection opened with nova-2-meeting model");
        console.log("\u{1F399}\uFE0F Configuration: 48kHz sample rate, diarization enabled");
        console.log("\u2139\uFE0F Note: Speaker detection needs 20-30 seconds of audio to build profiles");
        console.log("\u2139\uFE0F Both speakers must speak for accurate diarization");
        dgConnection.on(LiveTranscriptionEvents.Transcript, (data) => {
          const transcript = data.channel?.alternatives?.[0]?.transcript;
          const words = data.channel?.alternatives?.[0]?.words || [];
          const isFinal = data.is_final;
          const confidence = data.channel?.alternatives?.[0]?.confidence || 0;
          const entities = data.channel?.alternatives?.[0]?.entities || [];
          if (isFinal && words.length > 0) {
            const speakersFound = new Set(words.map((w) => w.speaker).filter((s) => s !== void 0));
            console.log(`\u{1F399}\uFE0F Final transcript: "${transcript?.substring(0, 50)}..." - Speakers: [${Array.from(speakersFound).join(", ")}]`);
          }
          const speakerSegments = [];
          let currentSpeaker = null;
          let currentText = "";
          const speakerValues = words.map((w) => w.speaker).filter((s) => s !== void 0);
          const hasSpeakerInfo = speakerValues.length > 0;
          const hasMultipleSpeakers = new Set(speakerValues).size > 1;
          if (isFinal && hasMultipleSpeakers) {
            console.log(`\u{1F465} Multiple speakers detected in this segment!`);
          }
          words.forEach((word) => {
            const speaker = word.speaker !== void 0 ? word.speaker : 0;
            const wordText = word.punctuated_word || word.word || "";
            if (currentSpeaker === null || currentSpeaker === speaker) {
              currentSpeaker = speaker;
              currentText += (currentText ? " " : "") + wordText;
            } else {
              if (currentText.trim()) {
                speakerSegments.push({ speaker: currentSpeaker, text: currentText.trim() });
              }
              currentSpeaker = speaker;
              currentText = wordText;
            }
          });
          if (currentText.trim() && currentSpeaker !== null) {
            speakerSegments.push({ speaker: currentSpeaker, text: currentText.trim() });
          }
          if (transcript && clientWs.readyState === WebSocket.OPEN) {
            const sendSegments = hasSpeakerInfo && speakerSegments.length > 0 ? speakerSegments : void 0;
            clientWs.send(JSON.stringify({
              type: "transcript",
              transcript,
              is_final: isFinal,
              confidence,
              speaker_segments: sendSegments,
              entities: entities.length > 0 ? entities : void 0
            }));
          }
        });
        dgConnection.on(LiveTranscriptionEvents.UtteranceEnd, (data) => {
          console.log("\u{1F3A4} Utterance ended - speaker turn complete");
        });
        clientWs.on("message", (data) => {
          try {
            if (dgConnection.getReadyState() === 1) {
              if (Buffer.isBuffer(data) && data.length === 0) {
                console.log("\u{1F493} Keepalive ping received");
                return;
              }
              if (Buffer.isBuffer(data)) {
                dgConnection.send(new Uint8Array(data).buffer);
              } else if (data instanceof ArrayBuffer) {
                dgConnection.send(data);
              } else if (Array.isArray(data)) {
                const combined = Buffer.concat(data);
                dgConnection.send(new Uint8Array(combined).buffer);
              }
            }
          } catch (error) {
            console.error("Error processing client message:", error);
          }
        });
        clientWs.on("close", () => {
          console.log("\u{1F44B} Client disconnected from transcription stream");
          try {
            if (dgConnection.getReadyState() !== 3) {
              dgConnection.finish();
            }
          } catch (error) {
            console.error("Error closing Deepgram connection:", error);
          }
        });
        clientWs.on("error", (error) => {
          console.error("Client WebSocket error:", error);
          try {
            if (dgConnection.getReadyState() !== 3) {
              dgConnection.finish();
            }
          } catch (cleanupError) {
            console.error("Error cleaning up Deepgram connection on client error:", cleanupError);
          }
        });
      });
    } catch (error) {
      console.error("Failed to setup Deepgram connection:", error);
      console.error("Error stack:", error?.stack);
      try {
        if (clientWs.readyState === WebSocket.OPEN) {
          clientWs.send(JSON.stringify({
            type: "error",
            error: "Failed to initialize transcription service"
          }));
        }
      } catch (sendError) {
        console.error("Error sending error message to client:", sendError);
      }
      try {
        clientWs.close();
      } catch (closeError) {
        console.error("Error closing client WebSocket:", closeError);
      }
    }
  });
  return router4;
}

